%%%%%%%%%% Function fXrayOutV07.m %%%%%%%%%%% Kei Nakamura% Created on Thursday, March 9th 2006.% Modified on Thursday, November 22nd 2007.%% function [img cntX] = fXrayOutV06(img,fct,pit,minX)% img:      input and output image% cntX:     counts of taken out pixel% fct:      factor to take out the point% pit:      depth of the pit% minX:      minimun counts to be taken% takes out X-ray noise out of an image, do only one time.% ver.5: impliment minimum counts% ver.6: edge problem% ver.7: edge problem (v6 cut too much)function [img,cntX] = fXrayOutV07(img,fct,pit,minX)[szy,szx] = size(img);%vrtImg = zeros(szy+2*pit,szx+2*pit);%vrtImg(1+pit:end-pit,1+pit:end-pit) = img;edgT = img(1:pit,:);                % edge top for virtual imageedgB = img(end-pit+1:end,:);        % edge for bottomedgL = img(:,1:pit);                % edge leftedgR = img(:,end-pit+1:end);        % edge rightcrn = zeros(pit,pit);img = [crn,edgT,crn;edgL,img,edgR;crn,edgB,crn];%img = vrtImg;imgT = 0.5*img(1:pit,:);                    % top part of the imageimgB = 0.5*img(end-pit+1:end,:);            % bottom part of the imageimgL = 0.5*img(pit+1:end-pit,1:pit);        % left part of the imageimgR = 0.5*img(pit+1:end-pit,end-pit+1:end);% right part of the imagecnt = 1e10; cntX = 0; cntCmp = 1;imgObj0 = img(1+pit:end-pit,1+pit:end-pit);     % object of the processwhile cnt>0    imgRfT = 0.25*img(1:end-2*pit,1+pit:end-pit);    % top reference/4    imgRfB = 0.25*img(1+2*pit:end,1+pit:end-pit);    % bottom reference/4    imgRfL = 0.25*img(1+pit:end-pit,1:end-2*pit);    % left reference/4    imgRfR = 0.25*img(1+pit:end-pit,1+2*pit:end);    % right reference/4    imgRf = imgRfT + imgRfB + imgRfL + imgRfR;           % averaged reference    imgObj1 = imgObj0 - fct*imgRf;                   % factored subtraction        imgX = imgObj1>0&imgObj0>=minX;                               % xray ->1    %cntCmp = cnt-sum(sum(imgX));    cnt = sum(sum(imgX));                            % number of x-ray    imgX = imgX.*imgRf;                              % xray -> averaged value    imgN = ~(imgObj1>0&imgObj0>=minX);                            % <threshold ->1    imgN = imgN.*imgObj0;                           % nonXray -> left    imgObj0 = imgX + imgN;                          % x-ray out image    cntX = cntX + cnt;                              % total counts of X-ray        imgM = [imgL imgObj0 imgR];             % middle part of the image(new)    img = [imgT;imgM;imgB];                 % processed image    endimg = img(1+pit:end-pit,1+pit:end-pit);
